/* 카드 이동 library.moveCard */
UPDATE TB_KNOW_CARD
SET CATEGORY_ID = #{targetCategoryId}
    , SORT_ORD = (
        SELECT maxOrd + 1 FROM (
            SELECT IFNULL(MAX(T.SORT_ORD), 0) AS maxOrd
            FROM TB_KNOW_CARD T
            WHERE T.CATEGORY_ID = #{targetCategoryId}
              AND T.USER_ID = #{userId}
        ) AS tmp
    )
    , MODIFY_DT = NOW()
WHERE CARD_ID = #{cardId}
  AND USER_ID = #{userId}

